const error = $input.first().json;
const today = new Date().toISOString().split('T')[0];
const ts = new Date().toISOString();

const workflowName = error.workflow?.name || 'Unknown';
const workflowId = error.workflow?.id || '';
const executionId = error.execution?.id || '';
const nodeName = error.execution?.lastNodeExecuted || 'Unknown';
const errorMsg = error.execution?.error?.message || JSON.stringify(error).substring(0, 500);
const errorStack = error.execution?.error?.stack || '';

const n8nHost = 'http://192.168.1.121:5678';
const execLink = executionId ? `${n8nHost}/workflow/${workflowId}/executions/${executionId}` : `${n8nHost}/workflow/${workflowId}`;

const html = `<!DOCTYPE html><html><head><meta name="viewport" content="width=device-width,initial-scale=1"></head><body style="margin:0;background:#f3f4f6;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;color:#1a1a1a;line-height:1.5">
<div style="max-width:600px;margin:0 auto;background:#ffffff">
<noscript style="display:block;padding:8px 16px;background:#fef2f2;color:#991b1b;font-size:12px;border-bottom:1px solid #fecaca">n8n error: ${workflowName} — ${nodeName} @ ${ts}</noscript>
<div style="background:#dc2626;color:white;padding:20px">
  <h1 style="margin:0;font-size:18px;font-weight:700">🚨 Workflow Error</h1>
  <p style="margin:6px 0 0;font-size:13px;opacity:0.9">${workflowName} · ${ts}</p>
</div>
<div style="padding:18px 20px">
  <h2 style="margin:0 0 8px;font-size:15px;color:#1a1a1a">⚠️ Failure summary</h2>
  <table style="width:100%;border-collapse:collapse;font-size:13px">
    <tr><td style="padding:8px;background:#f9fafb;font-weight:600;width:140px">Workflow</td><td style="padding:8px">${workflowName}</td></tr>
    <tr><td style="padding:8px;background:#f9fafb;font-weight:600">Failed Node</td><td style="padding:8px">${nodeName}</td></tr>
    <tr><td style="padding:8px;background:#f9fafb;font-weight:600">Execution ID</td><td style="padding:8px;font-family:monospace;font-size:12px">${executionId || 'n/a'}</td></tr>
    <tr><td style="padding:8px;background:#f9fafb;font-weight:600">Time (UTC)</td><td style="padding:8px">${ts}</td></tr>
  </table>
  <h2 style="margin:18px 0 8px;font-size:15px;color:#1a1a1a">📋 Error message</h2>
  <pre style="background:#1f2937;color:#fca5a5;padding:14px;border-radius:6px;font-size:12px;line-height:1.6;overflow-x:auto;white-space:pre-wrap;word-wrap:break-word">${(errorMsg + (errorStack ? '\n\nStack:\n' + errorStack : '')).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}</pre>
  <h2 style="margin:18px 0 8px;font-size:15px;color:#1a1a1a">🔧 Quick actions</h2>
  <p style="margin:0 0 10px"><a href="${execLink}" style="display:inline-block;background:#0066cc;color:white;padding:10px 16px;border-radius:6px;text-decoration:none;font-weight:600;font-size:13px">Open execution in n8n →</a></p>
  <p style="margin:8px 0 0;font-size:12px;color:#6b7280">Recovery checklist: 1) Open the execution above. 2) Inspect the failed node's input. 3) Re-run from that node once root cause is fixed. Run logs are in <code>99_System/logs/errors-${today}.json</code>.</p>
</div>
<div style="background:#1a1a1a;color:#9ca3af;padding:12px 20px;text-align:center;font-size:11px">Life OS Error Handler · ${today}</div>
</div></body></html>`;

const log = JSON.stringify({
  workflow: 'error-handler',
  source_workflow: workflowName,
  source_workflow_id: workflowId,
  source_node: nodeName,
  source_execution_id: executionId,
  execution_link: execLink,
  error: errorMsg,
  error_stack: errorStack,
  timestamp: ts
}, null, 2);

return [{ json: {
  subject: `🚨 n8n Error: ${workflowName} — ${nodeName}`,
  html, today, ts,
  logKey: `99_System/logs/errors-${today}.json`,
  logContent: log
}}];

const content = $json.logContent;
const key = $json.logKey;
const buf = Buffer.from(content, 'utf-8');
return [{ json: $json, binary: { data: { data: buf.toString('base64'), mimeType: 'application/json', fileName: key.split('/').pop(), fileExtension: 'json', fileSize: buf.length } } }];
